#include<bits/stdc++.h>
using namespace std;
int n, ant;
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		for (int j = i; j <= n; j++) {
			int k = n - i - j;
            if(k<j) continue;
			if (k == i || k == j || i == j) continue;
			int x = i, y = j, z = k;
			bool f1=0, f2=0, f3=0;
			while (x) {
				if (x % 10 == 3 || x % 10 == 7) {
					f1 = 1;
					break;
				}
				x /= 10;
			}
			while (y) {
				if (y % 10 == 3 || y % 10 == 7) {
					f2 = 1;
					break;
				}
				y /= 10;
			}
			while (z) {
				if (z % 10 == 3 || z % 10 == 7) {
					f3 = 1;
					break;
				}
				z /= 10;
			}
			if(f1||f2||f3) continue;
			ant++;
		}
	}
	cout<<ant;
	return 0;
}
